INSERT INTO public.agents (slug, name, description, category, icon, credit_cost, active) VALUES
('gerador-questoes', 'Gerador Inteligente de Questões de Prova', 'Transforme qualquer conteúdo de aula em avaliações completas com questões de múltipla escolha, V/F, dissertativas, casos clínicos e associação. Todas classificadas pela Taxonomia de Bloom com gabarito comentado e matriz de cobertura.', 'EdTech e Professores 4.0', 'ClipboardList', 1, true),
('tutor-socratico', 'Tutor Socrático Personalizado', 'Um tutor que NUNCA dá respostas diretas. Guia o aluno por perguntas progressivas até que ele chegue à conclusão correta por conta própria. Ideal para farmacologia, fisiologia e raciocínio clínico.', 'EdTech e Professores 4.0', 'GraduationCap', 1, true),
('construtor-rubricas', 'Construtor de Rubricas de Avaliação', 'Crie rubricas detalhadas para qualquer atividade avaliativa: seminários, TCCs, relatórios, projetos. Com critérios, descritores por nível de desempenho, alinhamento DCN/Bloom e versão simplificada para o aluno.', 'EdTech e Professores 4.0', 'FileSearch', 1, true),
('tradutor-abstracts', 'Tradutor Acadêmico e Corretor de Abstracts', 'Traduza textos científicos entre português e inglês com precisão terminológica. Inclui análise de conformidade IMRAD, adequação a normas de journals (APA, Vancouver), sugestões de keywords/MeSH e notas terminológicas.', 'Pesquisa Acadêmica e Dados', 'BookOpen', 1, true),
('gerador-mapas-mentais', 'Gerador de Mapas Mentais e Resumos Visuais', 'Transforme conteúdos extensos em mapas mentais hierárquicos, resumos esquemáticos, flashcards de revisão e roteiros de revisão espaçada. Material de estudo otimizado para máxima retenção.', 'EdTech e Professores 4.0', 'ScanEye', 1, true),
('revisor-apresentacoes', 'Revisor e Coach de Apresentações Científicas', 'Analise e otimize apresentações para defesas de TCC, congressos e seminários. Receba diagnóstico com notas por aspecto, roteiro otimizado slide a slide, dicas de oratória e sugestões de design.', 'Pesquisa Acadêmica e Dados', 'Stethoscope', 1, true);